// 1. Rescatamos la información del nodo Trigger (el primer nodo del flujo)
const datosIniciales = $('When Executed by Another Workflow').first().json;

return $input.all().map(item => {

  // 2. Agregamos el id_maestro_rel al flujo actual
  item.json.id_maestro_rel = datosIniciales.id_maestro_rel;

  // (Opcional) Agregamos el id_exp por si lo necesitas
  item.json.id_exp = datosIniciales.id_exp;

  // 3. Aplanamos el domicilio (lo sacamos de "output.domicilio" a "domicilio")
  if (item.json.output && item.json.output.domicilio) {
    item.json.domicilio = item.json.output.domicilio;
  }

  return item;
});;

// 1. Rescatamos la información del nodo Trigger (el primer nodo del flujo)
const datosIniciales = $('When Executed by Another Workflow').first().json;

return $input.all().map(item => {

  // 2. Agregamos el id_maestro_rel al flujo actual
  item.json.id_maestro_rel = datosIniciales.id_maestro_rel;

  // (Opcional) Agregamos el id_exp por si lo necesitas
  item.json.id_exp = datosIniciales.id_exp;

  // 3. Aplanamos el domicilio (lo sacamos de "output.domicilio" a "domicilio")
  if (item.json.output && item.json.output.domicilio) {
    item.json.domicilio = item.json.output.domicilio;
  }

  return item;
});;

// 1. Rescatamos los items originales que pasaron por la rama "pdf" (salida 0) del Switch
// Así recuperamos los IDs y nombres de archivo sin importar lo que haga Gemini
const documentosOriginales = $items("Switch", 0, 0);

return $input.all().map((item, index) => {
  // 2. Vinculamos el documento original con el resultado actual usando el índice (orden)
  const metadataOriginal = documentosOriginales[index].json;

  // 3. Intentamos encontrar el texto en las posibles rutas de respuesta de Gemini
  let rawText = "";

  if (item.json.text) {
    rawText = item.json.text; 
  } else if (item.json.candidates && item.json.candidates[0].content.parts[0].text) {
    rawText = item.json.candidates[0].content.parts[0].text; 
  } else if (item.json.content && item.json.content.parts && item.json.content.parts[0]) {
    rawText = item.json.content.parts[0].text; 
  } else if (item.json.message && item.json.message.content) {
    rawText = item.json.message.content;
  }

  // Si no encuentra nada, devuelve un error pero MANTIENE los IDs
  if (!rawText) {
    return {
      json: { 
        ...metadataOriginal,
        error: "No se encontró texto en la respuesta de la IA."
      }
    };
  }

  // 4. Limpieza de etiquetas Markdown de bloque de código
  let cleanJsonStr = rawText.replace(/```json/gi, "").replace(/```/g, "").trim();

  try {
    // 5. Parsear el JSON devuelto por la IA
    let parsedData = JSON.parse(cleanJsonStr);
    let elementosClave = parsedData.indexacion?.elementos_clave || {};

    // 6. Retornar los datos FUSIONADOS (IDs Originales + Resultados OCR)
    return {
      json: {
        // --- METADATOS ORIGINALES (AQUÍ OCURRE EL LINKEO) ---
        id_maestro_rel: metadataOriginal.id_maestro_rel,
        id_exp: metadataOriginal.id_exp,
        nombre_archivo: metadataOriginal.nombre_archivo,
        url_documento: metadataOriginal.url_base_datos,

        // --- RESULTADOS DEL OCR ---
        clasificacion: parsedData.clasificacion || "Sin clasificar",
        transcripcion: parsedData.transcripcion_completa || "",
        entidad: parsedData.indexacion?.entidad || "No detectada",
        titular: parsedData.indexacion?.titular || "No detectado",
        fecha_documento: parsedData.indexacion?.fecha || "No detectada",

        // Expande dinámicamente los datos extra (monto, fechas, etc.)
        ...elementosClave 
      }
    };

  } catch (e) {
    // Si la IA alucina o el JSON es inválido, mantenemos la vinculación para no perder el archivo
    return {
      json: {
        ...metadataOriginal,
        error: "Error de formato al parsear el JSON de la IA",
        raw_text: rawText.substring(0, 250) + "..."
      }
    };
  }
});

// Procesamos la salida del agente para dejar solo datos de tribunal y ubicación
return $input.all().map(item => {
  try {
    // 1. Extraer y limpiar el string de la IA
    let rawOutput = item.json.output;
    const jsonString = rawOutput.replace(/```json|```/gi, '').trim();

    // 2. Convertir a objeto JSON
    const dataIA = JSON.parse(jsonString);

    // 3. Retornar objeto filtrado sin 'tipo_rol' ni 'nombre_causa'
    return {
      json: {
        id_maestro: dataIA.id_maestro,
        tribunal: dataIA.tribunal,
        tribunal_region: dataIA.tribunal_region,
        tribunal_localidad: dataIA.tribunal_localidad,
        tipo_tribunal: dataIA.tipo_tribunal
      }
    };
  } catch (error) {
    return {
      json: {
        error: "Error en transformación de datos de competencia",
        detalles: error.message
      }
    };
  }
});

// 1. Rescatamos el ID maestro desde el nodo que inició el flujo
// Usamos el nombre del trigger común en tus sub-workflows
const datosIniciales = $('When Executed by Another Workflow').first().json;
const idMaestro = datosIniciales.id_maestro_rel || "Sin_ID";

// 2. Extraemos todas las filas del nodo anterior (Extract from File)
// $input.all() nos da todos los registros, los convertimos a un array simple
const todasLasFilas = $input.all().map(item => item.json);

// 3. Retornamos un ÚNICO objeto que contiene el ID para el filtro 
// y el JSON completo de la tabla para la columna 'tabla_transaccion'
return [{
  json: {
    id_maestro_rel: idMaestro,
    tabla_transaccion: {
      metadata: {
        total_filas: todasLasFilas.length,
        fecha_procesamiento: new Date().toISOString()
      },
      data: todasLasFilas
    }
  }
}];

// 1. Rescatamos la salida del nodo de análisis de audio
const aiResponse = $node["Analyze audio"].json;

return $input.all().map(item => {
  let rawText = "";

  // 2. Extraer el texto de la respuesta de Gemini (maneja distintos formatos de salida)
  if (aiResponse.text) {
    rawText = aiResponse.text;
  } else if (aiResponse.candidates && aiResponse.candidates[0].content.parts[0].text) {
    rawText = aiResponse.candidates[0].content.parts[0].text;
  }

  // 3. Limpieza de etiquetas Markdown (```json ... ```)
  let cleanJsonStr = rawText.replace(/```json/gi, "").replace(/```/g, "").trim();

  let parsedData = {};
  try {
    parsedData = JSON.parse(cleanJsonStr);
  } catch (e) {
    parsedData = { 
      transcripcion_completa: "Error al parsear transcripción",
      relato_paso_a_paso: rawText 
    };
  }

  // 4. Formateo de Monto (Uso de LaTeX para representación interna)
  // El monto se extrae del campo 'monto_total_estimado'
  const montoNumerico = parseFloat(parsedData.monto_total_estimado?.toString().replace(/[^0-9]/g, '') || 0);

  return {
    json: {
      // Metadatos para vinculación con Supabase [cite: 8, 22]
      id_maestro_rel: item.json.id_maestro_rel,
      nombre_demandado: item.json.nombre_demandado || "Cliente",

      // Datos para la plantilla de Word/Docs
      transcripcion: parsedData.transcripcion_completa || "No disponible",
      relato_hechos: parsedData.relato_paso_a_paso || "No disponible",
      tipo_fraude: parsedData.tipo_fraude || "No detectado",
      monto_formateado: "$" + montoNumerico.toLocaleString('es-CL'),
      claves_facilitadas: parsedData.claves_facilitadas ? "SÍ" : "NO",

      // Preparación para tabla Transacciones [cite: 17]
      monto_final: montoNumerico
    }
  };
});

// 1. Obtenemos el ID del documento generado y el ID Maestro
const docId = $node["Reemplazar Variables2"].json.id;
const idMaestro = $('When Executed by Another Workflow').first().json.id_maestro_rel;

// 2. Construimos la URL pública/interna de edición
const driveUrl = `https://docs.google.com/document/d/${docId}/edit`;

return [{
  json: {
    id_maestro_rel: idMaestro,
    url_drive: driveUrl,
    nombre_archivo: $node["Copiar Plantilla2"].json.name,
    tipo_evidencia: "DOCX"
  }
}];

const items = $input.all();
if (items.length === 0) return [{ json: { error: "Sin datos" } }];

const firstRow = items[0].json;
const headers = Object.keys(firstRow);

// Construcción del HTML compatible con Google Docs
let html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family: Arial, sans-serif;">
  <h2 style="color: #1F497D;">Detalle de Transacciones (Respaldo Original)</h2>
  <table border="1" cellpadding="6" cellspacing="0" width="100%" bordercolor="#cccccc">
    <thead>
      <tr>`;

for (const header of headers) {
    html += `<th bgcolor="#1F497D" align="left"><font color="#ffffff"><b>${header}</b></font></th>`;
}
html += `</tr></thead><tbody>`;

let rowIndex = 0;
for (const item of items) {
  const row = item.json;
  const bgColor = (rowIndex % 2 === 0) ? "#FFFFFF" : "#E6EDF5";
  html += `<tr>`;
  for (const header of headers) {
      const cellValue = row[header] !== undefined && row[header] !== null ? row[header] : '---';
      html += `<td bgcolor="${bgColor}"><font color="#000000">${cellValue}</font></td>`;
  }
  html += `</tr>`;
  rowIndex++;
}
html += `</tbody></table></body></html>`;

// Recuperar ID Maestro para vinculación con Expedientes_Core
let idMaestro = "Sin_ID";
try {
  // Buscamos el ID en el nodo de inicio del flujo
  idMaestro = $('When Executed by Another Workflow').first().json.id_maestro_rel;
} catch (e) {}

const buffer = Buffer.from(html, 'utf8');

return [{
  json: {
    id_maestro_rel: idMaestro,
    tipo_evidencia: "HTML_CONVERT"
  },
  binary: {
    data: { 
      data: buffer.toString('base64'),
      mimeType: 'application/vnd.google-apps.document', 
      fileName: `${idMaestro}_transacciones.html`
    }
  }
}];

